module freq_div(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);

    reg [6:0] cnt_100 = 0;
    reg [1:0] cnt_10 = 0;
    reg [3:0] cnt_1 = 0;

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_50 <= 0;
            CLK_10 <= 0;
            CLK_1 <= 0;
            cnt_100 <= 0;
            cnt_10 <= 0;
            cnt_1 <= 0;
        end else begin
            // 50MHz clock
            if (cnt_100 == 99) begin
                CLK_50 <= ~CLK_50;
                cnt_100 <= 0;
            end else begin
                cnt_100 <= cnt_100 + 1;
            end

            // 10MHz clock
            if (cnt_10 == 4) begin
                CLK_10 <= ~CLK_10;
                cnt_10 <= 0;
            end else begin
                cnt_10 <= cnt_10 + 1;
            end

            // 1MHz clock
            if (cnt_1 == 9) begin
                CLK_1 <= ~CLK_1;
                cnt_1 <= 0;
            end else begin
                cnt_1 <= cnt_1 + 1;
            end
        end
    end

endmodule
